    /**
    * Calls:
    * 1 - (200) POST:/annotation
    * 2 - (200) GET:/annotation/{variant}
    */
    @Test(timeout = 60000)
    public void test_18_getOnAnnotReturnsObject() throws Exception {
        
        ValidatableResponse res_0 = given().accept("application/json")
                .header("x-EMextraHeader123", "")
                .contentType("application/json")
                .body(" [ " + 
                    " \"zLVzrARV\", " + 
                    " \"_EM_484_XYZ_\", " + 
                    " \"_EM_485_XYZ_\", " + 
                    " \"_EM_486_XYZ_\" " + 
                    " ] ")
                .post(baseUrlOfSut + "/annotation?fields=kwX0sUzVVQ5")
                .then()
                .statusCode(200)
                .assertThat()
                .contentType("application/json")
                .body("size()", equalTo(4))
                .body("[0].'variant'", containsString("zLVzrARV"))
                .body("[0].'originalVariantQuery'", containsString("zLVzrARV"))
                .body("[0].'successfully_annotated'", equalTo(false))
                .body("[1].'variant'", containsString("_EM_484_XYZ_"))
                .body("[1].'originalVariantQuery'", containsString("_EM_484_XYZ_"))
                .body("[1].'successfully_annotated'", equalTo(false))
                .body("[2].'variant'", containsString("_EM_485_XYZ_"))
                .body("[2].'originalVariantQuery'", containsString("_EM_485_XYZ_"))
                .body("[2].'successfully_annotated'", equalTo(false))
                ; // Skipping assertions on the remaining 1 elements. This limit of 3 elements can be increased in the configurations
        String location_annotation__2 = res_0.extract().header("location");
        assertTrue(isValidURIorEmpty(location_annotation__2));
        
        given().accept("application/json")
                .header("x-EMextraHeader123", "42")
                .get(resolveLocation(location_annotation__2, baseUrlOfSut + "/annotation/_EM_428_XYZ_?token=7utPLI0z8BaB&fields=_EM_487_XYZ_&EMextraParam123=42"))
                .then()
                .statusCode(200)
                .assertThat()
                .contentType("application/json")
                .body("'variant'", containsString("_EM_428_XYZ_"))
                .body("'originalVariantQuery'", containsString("_EM_428_XYZ_"))
                .body("'successfully_annotated'", equalTo(false));
    }
    
    
